// Re-injects Saver's local (hand-written) Capacitor plugins into the iOS
// packageClassList after `cap sync`/`cap copy` regenerates it.
//
// In this project's SPM Capacitor setup, a local plugin (one with no npm
// package, wired via a CAP_PLUGIN macro) is ONLY registered if its class name
// is listed in ios/App/App/capacitor.config.json → packageClassList. That file
// is gitignored and fully regenerated by every `npx cap sync`/`npx cap copy`
// from the installed npm plugins alone, silently dropping the local ones — so
// the widget's sync() and the iCloud backup plugin start reporting
// "not implemented on ios". Run this right after any copy/sync to restore them.
import { readFileSync, writeFileSync } from "node:fs";

const CONFIG = "ios/App/App/capacitor.config.json";
const LOCAL_PLUGINS = ["SaverWidgetPlugin", "ICloudBackupPlugin"];

const cfg = JSON.parse(readFileSync(CONFIG, "utf8"));
cfg.packageClassList = cfg.packageClassList || [];

let added = 0;
for (const name of LOCAL_PLUGINS) {
  if (!cfg.packageClassList.includes(name)) { cfg.packageClassList.push(name); added++; }
}

if (added > 0) {
  writeFileSync(CONFIG, JSON.stringify(cfg, null, "\t") + "\n");
  console.log(`patch-ios-plugins: added ${added} local plugin(s) to packageClassList`);
} else {
  console.log("patch-ios-plugins: local plugins already present, nothing to do");
}
